import Image from "next/image";
import Link from "next/link";

interface FeaturedWork {
  title: string;
  subtitle: string;
  image: string;
  href?: string;
}

interface Project {
  title: string;
  description: string;
  tags: string[];
  href?: string;
}

const featuredWork: FeaturedWork[] = [
  {
    title: "Bluon AI MasterMechanic",
    subtitle: "Agentic AI for HVAC Techs",
    image: "/work/bluon-ai.png",
    href: "/work/bluon",
  },
  {
    title: "Moonwish",
    subtitle: "Building meaningful connections",
    image: "/work/moonwish.png",
    href: "/work/moonwish",
  },
];

const projects: Project[] = [
  {
    title: "Personal Website v3",
    description:
      "This website! Built with Next.js, Tailwind, and MDX. Features an AI chat, blog system, and bento grid layout.",
    tags: ["Next.js", "Tailwind", "MDX", "AI"],
    href: "https://github.com/Theonlyhamstertoh/weibozhang-v3",
  },
  {
    title: "AI Observability Tool",
    description:
      "A personal project exploring AI observability — tracking and understanding AI system behavior.",
    tags: ["AI", "Observability", "TypeScript"],
  },
];

function FeaturedCard({ work }: { work: FeaturedWork }) {
  const content = (
    <div className="group max-w-xl rounded-2xl bg-neutral-900 p-5 md:p-6 hover:bg-neutral-800 transition-colors duration-200 overflow-hidden">
      {/* Header */}
      <div className="flex items-center gap-2 mb-1">
        <span className="bg-blue-600 text-white text-xs font-bold px-2 py-0.5 rounded-md">
          Work
        </span>
        <h2 className="text-lg md:text-xl font-extrabold text-white tracking-tight">
          {work.title}
        </h2>
      </div>

      {/* Subtitle */}
      <p className="text-neutral-400 text-sm md:text-base mb-4">
        {work.subtitle}
      </p>

      {/* Screenshot */}
      <div className="rounded-xl overflow-hidden border border-neutral-800 ">
        <Image
          src={work.image}
          alt={`${work.title} screenshot`}
          width={600}
          height={400}
          className="w-full h-auto"
        />
      </div>
    </div>
  );

  if (work.href) {
    return <Link href={work.href}>{content}</Link>;
  }

  return content;
}

export default function WorkPage() {
  return (
    <div className="mx-auto max-w-10/12 w-full px-6 py-10">
      <h1 className="text-3xl font-bold mb-8">Work</h1>

      {/* Featured Work */}
      <div className="flex flex-col md:flex-row flex-wrap gap-6 mb-12">
        {featuredWork.map((work) => (
          <FeaturedCard key={work.title} work={work} />
        ))}
      </div>

      {/* Projects */}
      <h2 className="bg-sky-950 text-sky-500 p-1 rounded-lg font-extrabold text-3xl w-fit mb-4">
        Projects
      </h2>
      <div className="flex flex-wrap gap-4">
        {projects.map((project) => {
          const content = (
            <div className="group flex flex-col duration-100 h-66 w-full md:w-72 gap-1 rounded-xl bg-neutral-900 p-6 hover:outline-neutral-700 hover:outline hover:bg-neutral-800 transition-colors">
              <span className="text-2xl font-semibold text-neutral-200 group-hover:text-white">
                {project.title}
              </span>
              <p className="text-neutral-500 text-sm mt-1 line-clamp-3">
                {project.description}
              </p>
              <div className="flex flex-wrap gap-2 mt-auto">
                {project.tags.map((tag) => (
                  <span
                    key={tag}
                    className="text-xs font-medium text-neutral-400 bg-neutral-800 group-hover:bg-neutral-700 px-2 py-0.5 rounded-full transition-colors"
                  >
                    {tag}
                  </span>
                ))}
              </div>
            </div>
          );

          return project.href ? (
            <Link
              key={project.title}
              href={project.href}
              target="_blank"
              rel="noopener noreferrer"
            >
              {content}
            </Link>
          ) : (
            <div key={project.title}>{content}</div>
          );
        })}
      </div>
    </div>
  );
}
